using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var requestUri = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetAsync(requestUri);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<SearchResult>();

            // Extract abstract if available
            if (root.TryGetProperty("AbstractText", out var abstractText) &&
                abstractText.GetString() is { Length: > 0 } abs)
            {
                var abstractUrl = root.TryGetProperty("AbstractURL", out var aUrl)
                    ? aUrl.GetString() ?? ""
                    : "";

                results.Add(new SearchResult("Summary", abs, abstractUrl));
            }

            // Extract related topics
            if (root.TryGetProperty("RelatedTopics", out var topics) &&
                topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var topic in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;

                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } t)
                    {
                        var url = topic.TryGetProperty("FirstURL", out var firstUrl)
                            ? firstUrl.GetString() ?? ""
                            : "";

                        results.Add(new SearchResult("Related", t, url));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the search query.";
            }

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Please try again with a different query.";
        }
    }

    private sealed record SearchResult(string Type, string Snippet, string Url);
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with research findings")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes. Use this to review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet. Use SaveNote to record research findings.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");

        for (int i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"\n--- Note {i + 1}: {note.Title} ---");
            sb.AppendLine($"Recorded: {note.Timestamp:u}");
            sb.AppendLine(note.Content);
        }

        return sb.ToString();
    }

    [Description("Searches notes for a keyword. Returns matching notes.")]
    public string SearchNotes(
        [Description("The keyword to search for in note titles and content")] string keyword)
    {
        var matches = _notes
            .Where(n => n.Title.Contains(keyword, StringComparison.OrdinalIgnoreCase) ||
                        n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
        {
            return $"No notes found matching '{keyword}'.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Found {matches.Count} note(s) matching '{keyword}':");

        foreach (var note in matches)
        {
            sb.AppendLine($"\n- {note.Title}: {note.Content[..Math.Min(note.Content.Length, 200)]}");
        }

        return sb.ToString();
    }

    private sealed record Note(string Title, string Content, DateTime Timestamp);
}

