};

// Create the agent with tools and instructions
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the SearchWebAsync tool
        2. Taking notes on key findings using the SaveNote tool
        3. Performing multiple searches to cover different aspects of the topic
        4. Reviewing your notes with GetAllNotes before writing a final summary

        Always take structured notes as you research. Each note should capture a specific 
        finding or fact. After gathering enough information (at least 3-5 searches), 
        review all notes and provide a comprehensive summary to the user.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// Get the topic from the user
