using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

// Validate configuration
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build the chat client via MEAI abstraction
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .AsChatClient(modelId);

// Create tool instances
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var webSearchTool = new WebSearchTool(httpClient);
var noteTakingTool = new NoteTakingTool();

// Create AI functions from tool methods
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTakingTool.SaveNote),
    AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
    AIFunctionFactory.Create(noteTakingTool.SearchNotes),
};

// Create the agent with tools and instructions
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the SearchWebAsync tool
        2. Taking notes on key findings using the SaveNote tool
        3. Performing multiple searches to cover different aspects of the topic
        4. Reviewing your notes with GetAllNotes before writing a final summary

        Always take structured notes as you research. Each note should capture a specific 
        finding or fact. After gathering enough information (at least 3-5 searches), 
        review all notes and provide a comprehensive summary to the user.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// Get the topic from the user
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine(new string('─', 40));

// Configure run options with temperature and token limits
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

// Run the agent in streaming mode
var userMessage = $"Please research the following topic thoroughly and provide a comprehensive summary: {topic}";

await foreach (var update in agent.RunStreamingAsync(userMessage, options: runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 40));
Console.WriteLine("Research complete.");

